var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼 이상으로 비정기 국무회의를 폐회하겠습니다.","JPN":"それでは、これで臨時国務会議を閉会します。","ENG":"Then, the irregular cabinet meeting will end here.","TWN":"那麼，本次的臨時國務會議就此結束。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"참석자 분들께서는 각자 맡은 바 소임에 힘써 주십시오. 이상입니다.","JPN":"ご参席の方々におかれましては、各自の役割に尽力してください。以上です。","ENG":"Attendees, please perform your duties with diligence. That is all.","TWN":"請各位各司其職、各盡其責，以上。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"각하, 잠시 괜찮으시겠습니까.","JPN":"閣下、少々よろしいでしょうか。","ENG":"Sir, may I have a minute?","TWN":"總務，我有些話想和您談談。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"오, 자네로군. 그렇지 않아도 따로 한 번 부르려던 참이었는데.","JPN":"おお、君か。ちょうど個別に話をせねばと思っていたところだったんだ。","ENG":"Oh, it's you. I was actually going to call you in myself.","TWN":"喔，是你。我剛想要單獨和你談呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그래, 일처리는 어떻게 되었나?","JPN":"それで、どうなったかね？","ENG":"So, how's the situation being handled?","TWN":"事情處理得怎麼樣？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"우선 우려하셨던 50호선 고속도로 인근에 발생한 침식체들에 대해선…","JPN":"まず、ご心配なさっていた50号線高速道路の近くで発生した侵食体については……","ENG":"First of all, about the C.O.s that appeared on I-50...","TWN":"關於您之前擔憂的50號線高速公路附近出沒的侵蝕體……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"발생 당시 있던 용병들과 샤레이드의 증원에 의해 제압되었습니다.","JPN":"発生当時、そこにいた傭兵たちとシャレードの増援により、制圧に成功しました。","ENG":"They were suppressed by the mercenaries that were in the area and reinforcements from Charade.","TWN":"已被案發現場的傭兵和查雷德的支援人力成功制伏。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"샤레이드?","JPN":"シャレード？","ENG":"Charade?","TWN":"查雷德？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"오지만디아스를 태스크포스 자격으로 파견했더군요.","JPN":"オジマンディアスをタスクフォースの資格で派遣したのです。","ENG":"They deployed Ozymandias as a TASKFORCE.","TWN":"他們派來奧茲曼迪亞斯來。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"아무래도 루이제 슈나이더 건과 관련해서, 미리 준비를 해 둔 모양새였습니다.","JPN":"どうやらルイーゼ・シュナイダーの件に関して、あらかじめ準備しておいた様子でした。","ENG":"It seemed that they had prepared in advance regarding the Louise Schneider case.","TWN":"可能是想為露易絲·修奈德事件提前做好準備。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"흐음…. 그렇군. 좋아.","JPN":"ふむ……そうか。よろしい。","ENG":"Hmm... I see. Very well.","TWN":"嗯……原來如此，好。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그 다음은, 수도 상공에 출몰했던 침식체에 대해서입니다만….","JPN":"続いて、首都上空に出現した侵食体についてですが……","ENG":"Next is regarding the C.O. that appeared in the capital's airspace...","TWN":"然後是關於首都上空出沒的侵蝕體……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"그 건은 이제 되었네. 침식 청정지대로서 건재하다면 더 들쑤실 것 없어.","JPN":"その件はもういい。侵食清浄区域として健在ならこれ以上騒ぎ立てる必要はない。","ENG":"I've heard enough about that one. No need to address it as long as the city is still a C.O.-free zone.","TWN":"那事就到此為止，既然已經恢復為無侵蝕區域，那就這樣吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"브레히트 중사라고 했던가?","JPN":"ブレヒト軍曹だったか？","ENG":"Sergeant Brecht, was it?","TWN":"她叫布萊希特中士？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"요새 국민들 사이에서 인기가 하늘을 찌르더군.","JPN":"最近、国民の間で人気がうなぎ登りのようだな。","ENG":"Her popularity seems to have skyrocketed among the people.","TWN":"她最近似乎很受國民愛戴。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"이미 정부군에서 영웅으로 선전하던 부사관입니다.","JPN":"過去に政府軍で英雄と称していた下士官です。","ENG":"She is an NCO who has already been promoted as a hero by the government.","TWN":"她之前就是一位被誇為英雄的中士。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"이 기세라면 최연소 의원도 가능할 것으로 보입니다. 이미 접촉 의사를 타진하는 자들도….","JPN":"この勢いなら、最年少議員も可能かと。すでに接触を試みようとする者たちも……","ENG":"At this rate, she might become the youngest council member in the history of our country. Some have already contacted her...","TWN":"如果能延續這股氣勢，甚至當選最年輕議員也有可能。已經有些人在試圖去接觸她……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"어떻게 처리할 수 없겠나?","JPN":"何とか処理はできないか？","ENG":"Can you handle it for me?","TWN":"你說能不能處理？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"각하, 무슨 말씀이신지….","JPN":"閣下、それはどういう……？","ENG":"Sir, I don't understand...","TWN":"我沒聽明白您的意思……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"지금 같은 시기에 여론이 기우는 건 좋지 않아.","JPN":"今のような時期に世論が傾くことはよくない。","ENG":"We can't have the public be one-sided at a time like this.","TWN":"在這種時期，我們不能讓輿論倒向她那邊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"관건은 결국 브레히트 중사가 보유한 장비 아닌가?","JPN":"問題は、結局ブレヒト軍曹が保有している装備ではないかね？","ENG":"The important thing is Sergeant Brecht's gear, isn't it?","TWN":"關鍵點在於布萊希特中士的那件裝備不是嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……각하, 브레히트 중사는 목숨 바쳐 조국을 수호한 애국자입니다.","JPN":"……閣下、ブレヒト軍曹は命をかけて国を守った愛国者です。","ENG":"...Sir, Sergeant Brecht is a patriot who risked her life to defend this nation.","TWN":"……總理，布萊希特中士是捨生保衛國家的愛國者。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"예의 그 조직과의 접점이 끊어져 심려가 크신 건 알겠지만, 그런 정치적인 모험은….","JPN":"例の組織との接点が途絶え、ご不安な気持ちはお察ししますが、そのような政治的な冒険は……","ENG":"I understand you are concerned about losing contact with that organization, but to take a political risk like that is...","TWN":"我能理解您在擔心失去與那個組織的合作，但這樣的政治冒險還是……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"최소한 목줄을 매달 방안은 마련해야지 않나.","JPN":"少なくとも、首輪を付ける方法ぐらいは準備しておくべきだろう。","ENG":"Don't you think we should at least put a leash on her?","TWN":"至少應該制定一個牽制她的辦法。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"애초에 그 장비만 손에 넣을 수 있다면, 북방합의체도 우릴 함부로 여길 수 없어!","JPN":"あの装備さえ手中に収めておけば、北方合意体といえども我々を適当に扱うことはできないはずだ！","ENG":"Furthermore, if we are able to get our hands on that gear, the Northern Union won't be able to walk all over us!","TWN":"而且只要能拿到那件裝備，北方和議會也不會敢對我們怎麼樣！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"부모 신상을 파헤치든, 약에 중독시키든, 뭐든 써서라도….","JPN":"親の身の上を暴こうが、薬漬けにしようが、どんな手を使ってでも……","ENG":"Do anything you can. Threaten her using her parents, or even get her addicted to drugs, whatever it takes...","TWN":"調查父母的身世，或者給她下藥，不管用什麼辦法……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그만하십시오. 각하.","JPN":"おやめください、閣下。","ENG":"You mustn't, sir.","TWN":"別說了，總理。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"자네…. 지금 그 총으로 날 겨누는 건가?","JPN":"君……今その銃で、私を狙っているのか？","ENG":"You... Have you any idea who you're pointing that gun at?","TWN":"你……你竟敢拿槍指著我？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"충심의 표현입니다.","JPN":"忠心の表れとお思いください。","ENG":"It is a sign of my loyalty.","TWN":"這是我的忠心。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"남쪽에 좋은 별채를 물색해 두었습니다. 가서 한동안 휴식을 취하고 오시죠.","JPN":"南方にいい別荘を探しておきました。そこでしばらく休息をお取りください。","ENG":"I found a nice outhouse in the south. I suggest you go and rest for a while.","TWN":"我在南邊為您找了一間房子，請去那裡休息一陣子。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"이건 반역이야! 이러면 다른 의원들이 가만히 있을 것 같은가?","JPN":"これは反逆だ！　他の議員が黙っているとでも思うのか？","ENG":"This is treason! Do you really think the other members are going to allow this?","TWN":"這是造反！你以為其他議員們會撒手不管嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L45_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"글쎄요. 적어도 상당수는 관망하는 쪽을 택할 겁니다.","JPN":"さあ。少なくとも議員の相当数は傍観することを選ぶでしょう。","ENG":"Well, at least a majority will choose to stay on the sidelines.","TWN":"這個嘛，我猜大多數人會選擇觀望。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"뭐 하나. 어서 자택으로 모셔라.","JPN":"何をしている。早くご自宅までお送りしろ。","ENG":"What are you doing? Get him to his home.","TWN":"還愣著幹什麼，還不快送總理回去。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……목을 친 손인가.","JPN":"……上司に逆らってしまったか。","ENG":"...So I bit the hand that fed me.","TWN":"……摘了人家的烏紗帽，"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"이래서야 나도 모가지군.","JPN":"これで私もクビだな。","ENG":"I guess this won't end well for me, either.","TWN":"不知道我自己的還能不能保住。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};